let output = $json.output;

// If output is string → convert to JSON
if (typeof output === "string") {
  output = JSON.parse(output);
}

return [{
  json: {
    ...$json,
    action_items: (output.action_items || []).join(", "),
    follow_ups: (output.follow_ups || []).join(", "),
    risks: (output.risks || []).join(", ")
  }
}];

